def priority(item: float, bins: np.ndarray) -> np.ndarray:
    """Returns priority with which we want to add item to each bin.

    Args:
        item: Size of item to be added to the bin.
        bins: Array of capacities for each bin.

    Return:
        Array of same size as bins with priority score of each bin.
    """
    priorities = np.zeros_like(bins)
    for i in range(len(bins)):
        cap = bins[i]
        if cap == 0:
            priorities[i] = np.inf
            continue
        if item > cap * 2:
            priorities[i] = 5000 + (item - cap * 2) * 1000
            continue
        usage_ratio = item / cap
        penalty = 0
        for mul in [0.5, 0.75, 0.9, 0.99]:
            if usage_ratio > mul:
                penalty += (usage_ratio - mul) * 20
        if usage_ratio >= 1:
            base_priority = 100 * usage_ratio
        elif usage_ratio == 1:
            base_priority = 50
        else:
            try:
                log_val = np.log(1 - usage_ratio)
                base_priority = -log_val * 3
            except FloatingPointError:
                base_priority = 100
        if cap < 0.05:
            base_priority += 100
        elif cap < 0.2:
            base_priority += 30
        elif cap < 1:
            base_priority += 5
        for j in range(len(bins)):
            if i != j and abs(cap - bins[j]) < 0.1:
                penalty += 2
        priorities[i] = base_priority + penalty
    return priorities
